import{_ as r,o as l,c as i,ai as t}from"./chunks/framework.ampVZV4B.js";const b=JSON.parse('{"title":"Web 安全","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/security/web-security.md","filePath":"tech-system/security/web-security.md"}'),e={name:"tech-system/security/web-security.md"};function n(s,a,o,h,g,d){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="web-安全" tabindex="-1">Web 安全 <a class="header-anchor" href="#web-安全" aria-label="Permalink to “Web 安全”">​</a></h1><p>Web 安全涉及保护网络应用免受恶意攻击的技术和实践。包括防护常见漏洞、实施安全策略、加密敏感数据。</p><h2 id="常见攻击类型" tabindex="-1">常见攻击类型 <a class="header-anchor" href="#常见攻击类型" aria-label="Permalink to “常见攻击类型”">​</a></h2><h3 id="xss-跨站脚本攻击" tabindex="-1">XSS (跨站脚本攻击) <a class="header-anchor" href="#xss-跨站脚本攻击" aria-label="Permalink to “XSS (跨站脚本攻击)”">​</a></h3><ul><li><strong>原理</strong>: 注入恶意脚本、在受害者浏览器执行</li><li><strong>类型</strong>: 反射 XSS、存储 XSS、DOM XSS</li><li><strong>危害</strong>: 会话劫持、数据盗取、页面篡改</li></ul><h3 id="防护方法" tabindex="-1">防护方法 <a class="header-anchor" href="#防护方法" aria-label="Permalink to “防护方法”">​</a></h3><ul><li><strong>输入验证</strong>: 白名单验证、拒绝非预期输入</li><li><strong>输出编码</strong>: HTML/JavaScript/URL 编码、转义特殊字符</li><li><strong>CSP</strong>: 内容安全策略、脚本来源限制</li><li><strong>框架防护</strong>: 现代框架自动转义、Vue/React 防护</li></ul><h3 id="csrf-跨站请求伪造" tabindex="-1">CSRF (跨站请求伪造) <a class="header-anchor" href="#csrf-跨站请求伪造" aria-label="Permalink to “CSRF (跨站请求伪造)”">​</a></h3><ul><li><strong>原理</strong>: 在其他网站执行未授权操作、借用用户身份</li><li><strong>条件</strong>: 用户登录、浏览器自动认证、操作敏感</li><li><strong>危害</strong>: 转账、修改密码、删除数据</li></ul><h3 id="防护方法-1" tabindex="-1">防护方法 <a class="header-anchor" href="#防护方法-1" aria-label="Permalink to “防护方法”">​</a></h3><ul><li><strong>CSRF Token</strong>: 表单隐藏字段、验证 Token 有效性</li><li><strong>SameSite Cookie</strong>: 限制跨域 Cookie 发送</li><li><strong>验证来源</strong>: Origin/Referer 检查、二次认证</li></ul><h2 id="sql-注入" tabindex="-1">SQL 注入 <a class="header-anchor" href="#sql-注入" aria-label="Permalink to “SQL 注入”">​</a></h2><h3 id="攻击方式" tabindex="-1">攻击方式 <a class="header-anchor" href="#攻击方式" aria-label="Permalink to “攻击方式”">​</a></h3><ul><li><strong>拼接 SQL</strong>: 未经处理的用户输入、直接拼接</li><li><strong>注入恶意 SQL</strong>: 修改查询逻辑、删除数据、提升权限</li></ul><h3 id="防护方案" tabindex="-1">防护方案 <a class="header-anchor" href="#防护方案" aria-label="Permalink to “防护方案”">​</a></h3><ul><li><strong>参数化查询</strong>: PreparedStatement、绑定变量、SQL 引擎处理</li><li><strong>ORM 框架</strong>: Hibernate、SQLAlchemy、自动防护</li><li><strong>输入验证</strong>: 类型检查、长度限制、白名单</li><li><strong>最小权限</strong>: 数据库用户权限限制、受限操作</li></ul><h2 id="身份验证与授权" tabindex="-1">身份验证与授权 <a class="header-anchor" href="#身份验证与授权" aria-label="Permalink to “身份验证与授权”">​</a></h2><h3 id="身份验证" tabindex="-1">身份验证 <a class="header-anchor" href="#身份验证" aria-label="Permalink to “身份验证”">​</a></h3><ul><li><strong>密码</strong>: 强密码、盐值哈希（bcrypt、PBKDF2）、多因素认证</li><li><strong>Token</strong>: JWT、OAuth、长期凭证、无状态验证</li><li><strong>生物识别</strong>: 指纹、面部识别、物理安全</li></ul><h3 id="授权管理" tabindex="-1">授权管理 <a class="header-anchor" href="#授权管理" aria-label="Permalink to “授权管理”">​</a></h3><ul><li><strong>RBAC</strong>: 角色生成权限、层次关系、成本权衡</li><li><strong>ABAC</strong>: 属性权限控制、灵活精细、规则复杂</li><li><strong>权限验证</strong>: 每个请求验证、黑名单、白名单</li></ul><h2 id="加密与哈希" tabindex="-1">加密与哈希 <a class="header-anchor" href="#加密与哈希" aria-label="Permalink to “加密与哈希”">​</a></h2><h3 id="对称加密" tabindex="-1">对称加密 <a class="header-anchor" href="#对称加密" aria-label="Permalink to “对称加密”">​</a></h3><ul><li><strong>AES</strong>: 高性能、广泛应用、密钥管理困难</li><li><strong>应用</strong>: 数据加密、传输加密、备份加密</li></ul><h3 id="非对称加密" tabindex="-1">非对称加密 <a class="header-anchor" href="#非对称加密" aria-label="Permalink to “非对称加密”">​</a></h3><ul><li><strong>RSA</strong>: 密钥配对、数字签名、性能低</li><li><strong>ECC</strong>: 更小密钥、相同强度、计算高效</li></ul><h3 id="哈希函数" tabindex="-1">哈希函数 <a class="header-anchor" href="#哈希函数" aria-label="Permalink to “哈希函数”">​</a></h3><ul><li><strong>MD5/SHA1</strong>: 已破解、不建议使用</li><li><strong>SHA-256/512</strong>: 安全、广泛使用</li><li><strong>PBKDF2/bcrypt</strong>: 密码哈希、故意慢、盐值处理</li></ul><h2 id="安全通信" tabindex="-1">安全通信 <a class="header-anchor" href="#安全通信" aria-label="Permalink to “安全通信”">​</a></h2><h3 id="https-tls" tabindex="-1">HTTPS/TLS <a class="header-anchor" href="#https-tls" aria-label="Permalink to “HTTPS/TLS”">​</a></h3><ul><li><strong>SSL/TLS</strong>: 加密传输、身份认证、完整性检查</li><li><strong>证书</strong>: CA 签证、信任链、有效期限制</li><li><strong>协议版本</strong>: TLS 1.2+、向下兼容风险、性能平衡</li></ul><h3 id="密钥管理" tabindex="-1">密钥管理 <a class="header-anchor" href="#密钥管理" aria-label="Permalink to “密钥管理”">​</a></h3><ul><li><strong>生成</strong>: 强随机数、足够长度</li><li><strong>存储</strong>: 密钥库、HSM 硬件、权限隔离</li><li><strong>轮换</strong>: 定期更换、泄露后立即更换</li><li><strong>备份</strong>: 安全保存、灾难恢复</li></ul><h2 id="owasp-安全清单" tabindex="-1">OWASP 安全清单 <a class="header-anchor" href="#owasp-安全清单" aria-label="Permalink to “OWASP 安全清单”">​</a></h2><h3 id="常见漏洞顶-10" tabindex="-1">常见漏洞顶 10 <a class="header-anchor" href="#常见漏洞顶-10" aria-label="Permalink to “常见漏洞顶 10”">​</a></h3><ol><li><strong>注入</strong>: SQL 注入、命令注入、LDAP 注入</li><li><strong>损坏身份验证</strong>: 密码管理、会话管理失效</li><li><strong>敏感数据泄露</strong>: 未加密、传输安全、日志记录</li><li><strong>XML 外部实体 (XXE)</strong>: XML 解析、外部实体引用</li><li><strong>访问控制缺失</strong>: 权限检查不足、直接对象引用</li><li><strong>安全配置错误</strong>: 默认密码、不必要服务、调试模式</li><li><strong>XSS</strong>: 跨站脚本、反射存储 DOM</li><li><strong>不安全反序列化</strong>: 恶意对象、代码执行</li><li><strong>已知漏洞组件</strong>: 过期库、NPM 漏洞</li><li><strong>监控和日志缺失</strong>: 审计不足、告警缺人、溯源困难</li></ol><h2 id="安全实践" tabindex="-1">安全实践 <a class="header-anchor" href="#安全实践" aria-label="Permalink to “安全实践”">​</a></h2><h3 id="代码审查" tabindex="-1">代码审查 <a class="header-anchor" href="#代码审查" aria-label="Permalink to “代码审查”">​</a></h3><ul><li><strong>静态分析</strong>: 工具扫描、模式匹配、缺陷检测</li><li><strong>代码审查</strong>: 同行评审、知识共享、质量控制</li><li><strong>依赖扫描</strong>: NPM audit、OWASP DependencyCheck</li></ul><h3 id="安全测试" tabindex="-1">安全测试 <a class="header-anchor" href="#安全测试" aria-label="Permalink to “安全测试”">​</a></h3><ul><li><strong>渗透测试</strong>: 模拟破解、寻找漏洞、改善防御</li><li><strong>模糊测试</strong>: 随机输入、异常处理、边界条件</li><li><strong>安全扫描</strong>: OWASP ZAP、Burp Suite、自动化测试</li></ul><h3 id="安全部署" tabindex="-1">安全部署 <a class="header-anchor" href="#安全部署" aria-label="Permalink to “安全部署”">​</a></h3><ul><li><strong>最小权限</strong>: 最少权限原则、权限隔离</li><li><strong>隔离</strong>: 网络划分、容器隔离、虚拟化</li><li><strong>监控告警</strong>: 异常检测、入侵告警、应应机制</li></ul><h2 id="安全工具" tabindex="-1">安全工具 <a class="header-anchor" href="#安全工具" aria-label="Permalink to “安全工具”">​</a></h2><ul><li><strong>扫描</strong>: Nmap、Burp Suite、OWASP ZAP</li><li><strong>分析</strong>: Checkmarx、SonarQube、Fortify</li><li><strong>依赖</strong>: npm audit、OWASP DependencyCheck、Snyk</li><li><strong>加密</strong>: OpenSSL、Cryptography、PyNaCl</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to “最佳实践”">​</a></h2><h3 id="安全文化" tabindex="-1">安全文化 <a class="header-anchor" href="#安全文化" aria-label="Permalink to “安全文化”">​</a></h3><ul><li><strong>意识培训</strong>: 员工安全培训、定期更新</li><li><strong>标准规范</strong>: 安全编码、审核流程、政策制定</li><li><strong>应急预案</strong>: 事件响应、灾难恢复、沟通计划</li></ul><h3 id="持续改进" tabindex="-1">持续改进 <a class="header-anchor" href="#持续改进" aria-label="Permalink to “持续改进”">​</a></h3><ul><li><strong>漏洞追踪</strong>: 缺陷管理、优先级评估、及时修复</li><li><strong>补丁管理</strong>: 定期更新、兼容性测试、验证有效性</li><li><strong>审计日志</strong>: 变动记录、异常检测、合规证明</li></ul>',50)])])}const u=r(e,[["render",n]]);export{b as __pageData,u as default};
